export function keyFramedRaceHandler(){
    var chart = this.chart,
      scroll = chart.scroll,
      race = this;
    var frameInfo = this.keyFrameInfo;
    var frameData = race.data;
    if (scroll) {
      var scrollEnd = scroll.settings.orient
        ? scroll.settings.orient === "right" ||
          scroll.settings.orient === "left"
          ? scroll.brushExtent[1][1]
          : scroll.brushExtent[1][0]
        : scroll.brushScale.range()[1],
        chart = this.chart,
        scroll = chart.scroll,
        instance = scroll && scroll.brushInstance;

      if(scroll.overviewEnabled){
        scrollEnd = chart.overview.axes.x.scale.range()[1];
      }

      var index = Math.round(race.raceScale(instance.getSelection()[1]));
        frameInfo.index = index + 1 >=  this.chart.racing.positionArray.length ? 0 : index + 1;
      //update frameinfo.index to next position, using previous position index.

      

      var nextPos = this.chart.racing.positionArray[frameInfo.index];

      if (nextPos < instance.getSelection()[0]) {
        var index = Math.round(race.raceScale(instance.getSelection()[0]));
            frameInfo.index = index;
        nextPos = instance.getSelection()[0];
      }

      instance.setSelection(
        [instance.getSelection()[0], nextPos],
        0,
        chart.racing,
        true
      );

      var breakLoop = () => {
        return scroll.brushInstance.getSelection()[1] === scrollEnd;
      };
      return breakLoop;
    } else {
      //if scroll enabled - setting of data will occur in brush
      //if no scroll -no brush event, so we set data here
      //the frameData mentioned below, will help for dynamic data loading, frameData is chartOBj.userdata.keyframes, so when we update it in onload it will affect here also.
      frameInfo.index++;
      frameInfo.index = !frameInfo.index ? 0 : frameInfo.index;
      var _frame = frameData[frameInfo.index];
      race.setData(_frame, chart);
      race.render(chart);
      var breakLoop = () => 
      {
        return frameInfo.index + 1 >= frameData.length;
      }
      return breakLoop;
    }
}